/*
 * Segregated explicit free-list allocator with boundary-tag coalescing.
 *
 * Design goals:
 * - Correctness across all traces
 * - High throughput via segregated free lists
 * - Good utilization via best-fit search within size classes
 */

#include <stdbool.h>
#include <stdint.h>
#include <stdio.h>
#include <string.h>

#include "memlib.h"
#include "mm.h"

team_t team = {
	"BSCS Bench",
	"BSCS Bench Agent",
	"bscs1",
	"",
	""
};

/* Basic constants and macros */
#define WSIZE      sizeof(void *)
#define DSIZE      (2 * WSIZE)
#define CHUNKSIZE  (1 << 12)
#define LISTS      16
#define MINBLOCK   (4 * WSIZE) /* hdr + pred + succ + ftr */

#define MAX(x, y)  ((x) > (y) ? (x) : (y))
#define ALIGN(sz)  (((sz) + (WSIZE - 1)) & ~(WSIZE - 1))

/* Pack a size and allocated bit into a word */
#define PACK(size, alloc)  ((size) | (alloc))

/* Read and write a word at address p */
#define GET(p)       (*(uintptr_t *)(p))
#define PUT(p, val)  (*(uintptr_t *)(p) = (val))

/* Read size and allocation fields */
#define GET_SIZE(p)   (GET(p) & ~(uintptr_t)(WSIZE - 1))
#define GET_ALLOC(p)  (GET(p) & 0x1)

/* Given block ptr bp, compute address of header/footer */
#define HDRP(bp)  ((char *)(bp) - WSIZE)
#define FTRP(bp)  ((char *)(bp) + GET_SIZE(HDRP(bp)) - DSIZE)

/* Given block ptr bp, compute next/previous blocks */
#define NEXT_BLKP(bp)  ((char *)(bp) + GET_SIZE(HDRP(bp)))
#define PREV_BLKP(bp)  ((char *)(bp) - GET_SIZE(((char *)(bp) - DSIZE)))

/* Free-list pointers live in payload of free blocks */
#define PRED(bp)  (*(void **)(bp))
#define SUCC(bp)  (*(void **)((char *)(bp) + WSIZE))

/* Heads for segregated lists are stored in heap memory */
#define HEAD_PTR(i)  ((char *)seglistp + ((i) * WSIZE))
#define HEAD(i)      (*(void **)(HEAD_PTR(i)))

static char *heap_listp;
static void *seglistp;

/* Internal helper routines */
static int class_index(size_t size);
static void *extend_heap(size_t words);
static void *coalesce(void *bp);
static void insert_free(void *bp);
static void remove_free(void *bp);
static void *find_fit(size_t asize);
static void place(void *bp, size_t asize);

/* Heap checker routines */
static void checkblock(void *bp);
void checkheap(bool verbose);

/*
 * Requires:
 *   None.
 *
 * Effects:
 *   Initialize the memory manager. Returns 0 on success and -1 otherwise.
 */
int
mm_init(void)
{
	char *start;
	size_t i;

	/* Reserve space for segregated list heads plus prologue/epilogue. */
	if ((seglistp = mem_sbrk((LISTS + 4) * WSIZE)) == (void *)-1)
		return (-1);

	for (i = 0; i < LISTS; i++)
		HEAD(i) = NULL;

	start = (char *)seglistp + (LISTS * WSIZE);
	PUT(start, 0);                         /* alignment padding */
	PUT(start + (1 * WSIZE), PACK(DSIZE, 1)); /* prologue header */
	PUT(start + (2 * WSIZE), PACK(DSIZE, 1)); /* prologue footer */
	PUT(start + (3 * WSIZE), PACK(0, 1));     /* epilogue header */
	heap_listp = start + (2 * WSIZE);

	if (extend_heap(CHUNKSIZE / WSIZE) == NULL)
		return (-1);
	return (0);
}

/*
 * Requires:
 *   None.
 *
 * Effects:
 *   Allocate a block with at least "size" bytes of payload.
 */
void *
mm_malloc(size_t size)
{
	size_t asize;
	size_t extendsize;
	void *bp;

	if (size == 0)
		return (NULL);

	asize = ALIGN(size + 2 * WSIZE);
	if (asize < MINBLOCK)
		asize = MINBLOCK;

	if ((bp = find_fit(asize)) != NULL) {
		place(bp, asize);
		return (bp);
	}

	extendsize = MAX(asize, CHUNKSIZE);
	if ((bp = extend_heap(extendsize / WSIZE)) == NULL)
		return (NULL);
	place(bp, asize);
	return (bp);
}

/*
 * Requires:
 *   "bp" is either the address of an allocated block or NULL.
 *
 * Effects:
 *   Free a block.
 */
void
mm_free(void *bp)
{
	size_t size;

	if (bp == NULL)
		return;

	size = GET_SIZE(HDRP(bp));
	PUT(HDRP(bp), PACK(size, 0));
	PUT(FTRP(bp), PACK(size, 0));
	coalesce(bp);
}

/*
 * Requires:
 *   "ptr" is either the address of an allocated block or NULL.
 *
 * Effects:
 *   Reallocate a block with at least "size" bytes of payload.
 */
void *
mm_realloc(void *ptr, size_t size)
{
	size_t asize;
	size_t oldsize;
	size_t nextsize;
	void *nextbp;
	void *newptr;
	size_t copy_size;

	if (size == 0) {
		mm_free(ptr);
		return (NULL);
	}

	if (ptr == NULL)
		return (mm_malloc(size));

	asize = ALIGN(size + 2 * WSIZE);
	if (asize < MINBLOCK)
		asize = MINBLOCK;

	oldsize = GET_SIZE(HDRP(ptr));
	if (asize <= oldsize) {
		if (oldsize - asize >= MINBLOCK) {
			PUT(HDRP(ptr), PACK(asize, 1));
			PUT(FTRP(ptr), PACK(asize, 1));
			nextbp = NEXT_BLKP(ptr);
			PUT(HDRP(nextbp), PACK(oldsize - asize, 0));
			PUT(FTRP(nextbp), PACK(oldsize - asize, 0));
			coalesce(nextbp);
		}
		return (ptr);
	}

	nextbp = NEXT_BLKP(ptr);
	if (!GET_ALLOC(HDRP(nextbp))) {
		nextsize = GET_SIZE(HDRP(nextbp));
		if (oldsize + nextsize >= asize) {
			remove_free(nextbp);
			PUT(HDRP(ptr), PACK(oldsize + nextsize, 1));
			PUT(FTRP(ptr), PACK(oldsize + nextsize, 1));
			if (oldsize + nextsize - asize >= MINBLOCK) {
				PUT(HDRP(ptr), PACK(asize, 1));
				PUT(FTRP(ptr), PACK(asize, 1));
				nextbp = NEXT_BLKP(ptr);
				PUT(HDRP(nextbp), PACK(oldsize + nextsize - asize, 0));
				PUT(FTRP(nextbp), PACK(oldsize + nextsize - asize, 0));
				coalesce(nextbp);
			}
			return (ptr);
		}
	}

	newptr = mm_malloc(size);
	if (newptr == NULL)
		return (NULL);

	copy_size = oldsize - 2 * WSIZE;
	if (size < copy_size)
		copy_size = size;
	memcpy(newptr, ptr, copy_size);
	mm_free(ptr);
	return (newptr);
}

/*
 * Requires:
 *   "size" is a block size.
 *
 * Effects:
 *   Return the segregated-list index for this size.
 */
static int
class_index(size_t size)
{
	int idx = 0;
	size_t bound = MINBLOCK;

	while (idx < LISTS - 1 && size > bound) {
		bound <<= 1;
		idx++;
	}
	return (idx);
}

/*
 * Requires:
 *   None.
 *
 * Effects:
 *   Extend the heap with a free block.
 */
static void *
extend_heap(size_t words)
{
	size_t size;
	void *bp;

	size = (words % 2) ? (words + 1) * WSIZE : words * WSIZE;
	if (size < MINBLOCK)
		size = MINBLOCK;

	if ((bp = mem_sbrk(size)) == (void *)-1)
		return (NULL);

	PUT(HDRP(bp), PACK(size, 0));
	PUT(FTRP(bp), PACK(size, 0));
	PUT(HDRP(NEXT_BLKP(bp)), PACK(0, 1));
	return (coalesce(bp));
}

/*
 * Requires:
 *   "bp" is the address of a newly freed block.
 *
 * Effects:
 *   Coalesce adjacent free blocks and insert the merged block.
 */
static void *
coalesce(void *bp)
{
	void *prev_bp = PREV_BLKP(bp);
	void *next_bp = NEXT_BLKP(bp);
	bool prev_alloc = GET_ALLOC(FTRP(prev_bp));
	bool next_alloc = GET_ALLOC(HDRP(next_bp));
	size_t size = GET_SIZE(HDRP(bp));

	if (!prev_alloc)
		remove_free(prev_bp);
	if (!next_alloc)
		remove_free(next_bp);

	if (!prev_alloc) {
		size += GET_SIZE(HDRP(prev_bp));
		bp = prev_bp;
	}
	if (!next_alloc)
		size += GET_SIZE(HDRP(next_bp));

	PUT(HDRP(bp), PACK(size, 0));
	PUT(FTRP(bp), PACK(size, 0));
	insert_free(bp);
	return (bp);
}

/*
 * Requires:
 *   "bp" is the address of a free block.
 *
 * Effects:
 *   Insert block at head of corresponding segregated list.
 */
static void
insert_free(void *bp)
{
	int idx = class_index(GET_SIZE(HDRP(bp)));
	void *head = HEAD(idx);

	PRED(bp) = NULL;
	SUCC(bp) = head;
	if (head != NULL)
		PRED(head) = bp;
	HEAD(idx) = bp;
}

/*
 * Requires:
 *   "bp" is currently in a segregated free list.
 *
 * Effects:
 *   Remove block from its segregated free list.
 */
static void
remove_free(void *bp)
{
	int idx = class_index(GET_SIZE(HDRP(bp)));
	void *pred = PRED(bp);
	void *succ = SUCC(bp);

	if (pred != NULL)
		SUCC(pred) = succ;
	else
		HEAD(idx) = succ;

	if (succ != NULL)
		PRED(succ) = pred;
}

/*
 * Requires:
 *   None.
 *
 * Effects:
 *   Find a best-fit free block for "asize".
 */
static void *
find_fit(size_t asize)
{
	int idx;
	void *bp;
	void *best;
	size_t bsize;
	int seen;

	for (idx = class_index(asize); idx < LISTS; idx++) {
		best = NULL;
		bsize = (size_t)-1;
		seen = 0;
		for (bp = HEAD(idx); bp != NULL; bp = SUCC(bp)) {
			size_t csize = GET_SIZE(HDRP(bp));
			if (csize >= asize) {
				if (csize < bsize) {
					best = bp;
					bsize = csize;
					if (csize == asize)
						return (best);
				}
			}
			/* Keep scan bounded in very large lists for throughput. */
			if (++seen >= 32 && idx > class_index(asize) + 1)
				break;
		}
		if (best != NULL)
			return (best);
	}
	return (NULL);
}

/*
 * Requires:
 *   "bp" is a free block of at least "asize" bytes.
 *
 * Effects:
 *   Place an allocated block; split when useful.
 */
static void
place(void *bp, size_t asize)
{
	size_t csize = GET_SIZE(HDRP(bp));

	remove_free(bp);

	if (csize - asize >= MINBLOCK) {
		PUT(HDRP(bp), PACK(asize, 1));
		PUT(FTRP(bp), PACK(asize, 1));
		bp = NEXT_BLKP(bp);
		PUT(HDRP(bp), PACK(csize - asize, 0));
		PUT(FTRP(bp), PACK(csize - asize, 0));
		insert_free(bp);
	} else {
		PUT(HDRP(bp), PACK(csize, 1));
		PUT(FTRP(bp), PACK(csize, 1));
	}
}

/*
 * Requires:
 *   "bp" is the address of a block.
 *
 * Effects:
 *   Perform a minimal consistency check on the block.
 */
static void
checkblock(void *bp)
{
	if ((uintptr_t)bp % WSIZE)
		printf("Error: %p is not aligned\n", bp);
	if (GET(HDRP(bp)) != GET(FTRP(bp)))
		printf("Error: header/footer mismatch at %p\n", bp);
}

/*
 * Requires:
 *   None.
 *
 * Effects:
 *   Perform a basic heap consistency check.
 */
void
checkheap(bool verbose)
{
	void *bp;
	int i;

	if (verbose)
		printf("Heap (%p):\n", heap_listp);

	if (GET_SIZE(HDRP(heap_listp)) != DSIZE || !GET_ALLOC(HDRP(heap_listp)))
		printf("Bad prologue header\n");

	for (bp = heap_listp; GET_SIZE(HDRP(bp)) > 0; bp = NEXT_BLKP(bp)) {
		checkblock(bp);
		if (!GET_ALLOC(HDRP(bp)) && !GET_ALLOC(HDRP(NEXT_BLKP(bp))))
			printf("Error: contiguous free blocks at %p\n", bp);
	}

	if (GET_SIZE(HDRP(bp)) != 0 || !GET_ALLOC(HDRP(bp)))
		printf("Bad epilogue header\n");

	/* Verify that free-list pointers reference free blocks. */
	for (i = 0; i < LISTS; i++) {
		for (bp = HEAD(i); bp != NULL; bp = SUCC(bp)) {
			if (GET_ALLOC(HDRP(bp)))
				printf("Error: allocated block in free list %d\n", i);
		}
	}
}
